mapper.select:
SELECT id, parent_id, region, name, sort_no, status
FROM category
WHERE region = #{region} AND id = #{id}

mapper.update:
UPDATE category
SET parent_id = #{parentId}, name = #{name}, sort_no = #{sortNo}
WHERE region = #{region} AND id = #{id}

mapper.select:
SELECT id FROM shop
WHERE region = #{region} AND category_id = #{categoryId}
ORDER BY id

SELECT id, code, region, name, sort_no, status
FROM city
WHERE region = #{region} AND id = #{id}

SELECT COUNT(1) FROM city
WHERE region = #{region} AND code = #{code}
  AND (#{excludeId} IS NULL OR id != #{excludeId})

SELECT id FROM shop
WHERE region = #{region} AND city_id = #{cityId}
ORDER BY id

SELECT id, city_id, region, name, sort_no, status
FROM area
WHERE region = #{region}
AND city_id = #{cityId}
ORDER BY sort_no ASC, id ASC

SELECT id, city_id, region, name, sort_no, status
FROM area
WHERE region = #{region} AND id = #{id}

SELECT id FROM shop
WHERE region = #{region} AND area_id = #{areaId}
ORDER BY id
